import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.B72_uj9U.js";const g=JSON.parse('{"title":"Droid — Architecture","description":"","frontmatter":{},"headers":[],"relativePath":"research/agents/droid/architecture.md","filePath":"research/agents/droid/architecture.md"}'),n={name:"research/agents/droid/architecture.md"};function r(i,e,l,c,p,d){return a(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="droid-—-architecture" tabindex="-1">Droid — Architecture <a class="header-anchor" href="#droid-—-architecture" aria-label="Permalink to &quot;Droid — Architecture&quot;">​</a></h1><blockquote><p>How Factory&#39;s agent-native platform separates interface, agent core, model routing, and integrations into a layered architecture.</p></blockquote><h2 id="high-level-architecture" tabindex="-1">High-Level Architecture <a class="header-anchor" href="#high-level-architecture" aria-label="Permalink to &quot;High-Level Architecture&quot;">​</a></h2><p>Droid&#39;s architecture is designed around a central principle: <strong>the agent core is interface-agnostic</strong>. The same agent logic executes regardless of whether the developer interacts via IDE, web, CLI, Slack, Linear, or CI/CD. This is achieved through a layered architecture that cleanly separates concerns.</p><h3 id="layer-1-interface-layer-developer-surfaces" tabindex="-1">Layer 1: Interface Layer (Developer Surfaces) <a class="header-anchor" href="#layer-1-interface-layer-developer-surfaces" aria-label="Permalink to &quot;Layer 1: Interface Layer (Developer Surfaces)&quot;">​</a></h3><p>The outermost layer handles the diverse surfaces through which developers interact with Droid:</p><ul><li><strong>CLI</strong>: Terminal-based interactive agent for local development. Supports synchronous interaction and non-interactive CI/CD mode for pipeline automation.</li><li><strong>Web Workspaces</strong>: Cloud-hosted development environments at <code>app.factory.ai</code> with full browser-based interaction.</li><li><strong>Desktop IDE</strong>: Plugin-based integration into existing IDEs.</li><li><strong>Slack / Microsoft Teams</strong>: Conversational interface for delegating tasks from chat. Enables developers to kick off tasks (&quot;refactor the auth module&quot;) without switching tools.</li><li><strong>Linear</strong>: Direct integration with project management — Droids can pick up tasks from Linear issues.</li><li><strong>CI/CD Pipelines</strong>: Non-interactive mode where Droids run as part of build/deploy pipelines (e.g., auto-reviewing PRs, repairing GitHub Actions failures).</li></ul><p>Each interface adapter translates surface-specific interactions (Slack messages, IDE commands, terminal input) into a unified internal protocol that the agent core consumes.</p><h3 id="layer-2-droid-agent-core" tabindex="-1">Layer 2: Droid Agent Core <a class="header-anchor" href="#layer-2-droid-agent-core" aria-label="Permalink to &quot;Layer 2: Droid Agent Core&quot;">​</a></h3><p>The central processing layer contains:</p><ul><li><strong>Compaction Engine</strong>: Factory&#39;s proprietary context management system that enables multi-week sessions. Uses incremental compression with anchor points to preserve critical context while staying within token limits.</li><li><strong>Model Router</strong>: Vendor-agnostic model dispatch that routes requests to the appropriate LLM (OpenAI, Anthropic, Google, xAI, open-source, local). Teams can configure which models handle which task types.</li><li><strong>Tool System</strong>: Standardized tool interface (Read, Edit, Execute, Grep, Glob, and custom tools). Tracks tool calls for analytics (autonomy ratio, delegation patterns).</li><li><strong>Specification Mode</strong>: A planning capability that generates detailed implementation specs with mixed model support — reasoning models for spec generation, execution models for implementation.</li><li><strong>Session Manager</strong>: Maintains session state across interactions, enabling a developer to start a task in Slack and continue it in the CLI or web workspace.</li></ul><h3 id="layer-3-integration-layer" tabindex="-1">Layer 3: Integration Layer <a class="header-anchor" href="#layer-3-integration-layer" aria-label="Permalink to &quot;Layer 3: Integration Layer&quot;">​</a></h3><p>The deepest layer connects Droid to the developer&#39;s existing engineering ecosystem:</p><ul><li><strong>Source Code Management</strong> (required): GitHub Cloud, GitLab — Droid reads/writes code, creates PRs, reviews diffs.</li><li><strong>Project Management</strong> (recommended): Jira, Linear, Asana — Droid understands task context, links commits to tickets.</li><li><strong>Knowledge Management</strong> (recommended): Notion, Confluence, Google Drive — Droid references documentation and design decisions.</li><li><strong>Incident Management</strong> (recommended): Sentry, PagerDuty — Droid can respond to incidents, diagnose errors, and propose fixes.</li><li><strong>CI/CD &amp; Infrastructure</strong>: Docker, CircleCI, Google Cloud, Azure — pipeline integration and deployment awareness.</li><li><strong>Analytics &amp; Observability</strong>: Codecov, DX — code quality and developer experience metrics.</li></ul><h2 id="configuration-architecture" tabindex="-1">Configuration Architecture <a class="header-anchor" href="#configuration-architecture" aria-label="Permalink to &quot;Configuration Architecture&quot;">​</a></h2><p>Droid behavior is configured via <code>.droid.yaml</code> at the repository root. This file controls:</p><div class="language-yaml"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#89B4FA;">review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">  guidelines</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#89B4FA;"> path</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;**/api/**&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">      guideline</span><span style="color:#94E2D5;">:</span><span style="color:#A6E3A1;"> &quot;All API endpoints must have input validation&quot;</span></span>
<span class="line"><span style="color:#89B4FA;">  auto_review</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#89B4FA;">    enabled</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">    draft</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#89B4FA;">    bot</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> false</span></span>
<span class="line"><span style="color:#89B4FA;">    ignore_title_keywords</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;WIP&quot;</span><span style="color:#9399B2;">,</span><span style="color:#A6E3A1;"> &quot;DO NOT MERGE&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">    ignore_labels</span><span style="color:#94E2D5;">:</span><span style="color:#9399B2;"> [</span><span style="color:#A6E3A1;">&quot;droid-skip&quot;</span><span style="color:#9399B2;">]</span></span>
<span class="line"><span style="color:#89B4FA;">  pr_summary</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  file_summaries</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  tips</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  github_action_repair</span><span style="color:#94E2D5;">:</span><span style="color:#FAB387;"> true</span></span>
<span class="line"><span style="color:#89B4FA;">  path_filters</span><span style="color:#94E2D5;">:</span></span>
<span class="line"><span style="color:#9399B2;">    -</span><span style="color:#A6E3A1;"> &quot;!**/*.log&quot;</span></span></code></pre></div><p>Key configuration capabilities:</p><ul><li><strong>Path-specific review guidelines</strong>: Different rules for different parts of the codebase using fnmatch patterns.</li><li><strong>Auto-review triggers</strong>: Configurable conditions for automatic PR review (skip drafts, skip bot PRs, ignore WIP titles).</li><li><strong>GitHub Actions repair</strong>: Automatically suggest fixes when CI fails.</li><li><strong>Path filtering</strong>: Include/exclude files from review scope.</li></ul><h2 id="compute-architecture" tabindex="-1">Compute Architecture <a class="header-anchor" href="#compute-architecture" aria-label="Permalink to &quot;Compute Architecture&quot;">​</a></h2><p>Factory uses a <strong>single-tenant, sandboxed architecture</strong>:</p><ul><li>Each organization gets a dedicated VPC (Virtual Private Cloud) with isolated compute resources.</li><li><strong>Dedicated compute allocation</strong> ensures consistent performance regardless of platform load.</li><li>All data encrypted at rest (AES-256) and in transit (TLS 1.2+).</li><li>Strict permissions enforcement — Droid only accesses what the user already has permission to see.</li></ul><h2 id="observability-architecture-factory-analytics" tabindex="-1">Observability Architecture (Factory Analytics) <a class="header-anchor" href="#observability-architecture-factory-analytics" aria-label="Permalink to &quot;Observability Architecture (Factory Analytics)&quot;">​</a></h2><p>Built on <strong>OpenTelemetry</strong>, the analytics system captures:</p><ul><li>Token consumption (by model, user, date range, input/output split, cache efficiency)</li><li>Tool calls (by type: Read, Edit, Execute, Grep, Glob)</li><li>Activity metrics (DAU/WAU/MAU, session duration, client breakdown)</li><li>Productivity output (files created/edited, commits, PRs, language distribution)</li><li>Per-user breakdowns (days active, tokens consumed, tool calls)</li></ul><p>Data flows to either Factory&#39;s hosted dashboards (<code>app.factory.ai/analytics</code>) or exports via OTLP to Datadog, Grafana, New Relic, Splunk, or any compatible collector.</p><h3 id="analytics-api" tabindex="-1">Analytics API <a class="header-anchor" href="#analytics-api" aria-label="Permalink to &quot;Analytics API&quot;">​</a></h3><p>Four core endpoints power both dashboards and AI-generated reports:</p><table tabindex="0"><thead><tr><th>Endpoint</th><th>Question Answered</th></tr></thead><tbody><tr><td><code>/analytics/activity</code></td><td>Is my org using Droid?</td></tr><tr><td><code>/analytics/tokens</code></td><td>What are we spending?</td></tr><tr><td><code>/analytics/productivity</code></td><td>What is being shipped?</td></tr><tr><td><code>/analytics/tools</code></td><td>How is Droid being used?</td></tr></tbody></table><p>Droids can consume these endpoints directly to generate ROI reports, compare team adoption, or correlate AI usage with project delivery (e.g., linking token spend on a Linear project to story points completed).</p><h2 id="authentication-identity" tabindex="-1">Authentication &amp; Identity <a class="header-anchor" href="#authentication-identity" aria-label="Permalink to &quot;Authentication &amp; Identity&quot;">​</a></h2><ul><li><strong>SSO/SAML/OIDC</strong>: Integrates with any identity provider (Google Workspace, Okta, Azure AD).</li><li><strong>SCIM provisioning</strong>: Automated user lifecycle management.</li><li><strong>Repository permissions</strong>: Fine-grained access control mirroring source code management permissions.</li><li><strong>Audit logging</strong>: Comprehensive, configurable logging exportable to SIEM systems.</li></ul>`,32)])])}const h=t(n,[["render",r]]);export{g as __pageData,h as default};
